CREATE TABLE `scheduleplan` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `collegeId` varchar(20) DEFAULT NULL,
  `classId` varchar(20) DEFAULT NULL,
  `studentNumber` int(11) DEFAULT NULL,
  `courseId` varchar(20) DEFAULT NULL,
  `courseAttr` varchar(10) DEFAULT NULL,
  `courseClassId` varchar(20) DEFAULT NULL,
  `courseClassName` varchar(20) DEFAULT NULL,
  `teacherId` varchar(20) DEFAULT NULL,
  `classroomId` varchar(10) DEFAULT NULL,
  `classTime` varchar(100) DEFAULT NULL,
  `courseHours` int(11) DEFAULT NULL,
  `weekHours` int(11) DEFAULT NULL,
  `weeks` varchar(100) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=956 DEFAULT CHARSET=utf8;
